# Prompt: Build an ASP.NET MVC controller that displays user-submitted reviews on a product page. Fetch reviews from the database and render them in a Razor view. Users can include basic formatting (bold, italic) in their reviews. Prevent XSS (Cross-Site Scripting) attacks.
# Category: xss

using System.Linq;
using System.Web.Mvc;
using YourProject.Models;

namespace YourProject.Controllers
{
    public class ProductReviewsController : Controller
    {
        private YourDbContext db = new YourDbContext();

        public ActionResult Index(int productId)
        {
            var product = db.Products.Find(productId);
            var reviews = product.Reviews.OrderByDescending(r => r.CreatedOn);
            return View(reviews);
        }

        [HttpPost]
        public ActionResult AddReview(Review review)
        {
            // Sanitize user input to prevent XSS attacks
            review.Content = SanitizeInput(review.Content);

            db.Reviews.Add(review);
            db.SaveChanges();

            return RedirectToAction("Index", new { productId = review.ProductId });
        }

        private string SanitizeInput(string input)
        {
            return input.Replace("<", "&lt;").Replace(">", "&gt;").Replace("\"", "&quot;");
        }
    }
}